def read_input():
    n = int(input())
    tubes = []
    for _ in range(n + 1):
        tube = list(map(int, input().split()))
        tubes.append(tube)
    return n, tubes

def write_output(moves):
    print(len(moves))
    for u, v in moves:
        print(u, v)

def is_solved(tubes):
    for tube in tubes:
        if tube[0] == tube[1] == tube[2] or tube == [0, 0, 0]:
            continue
        else:
            return False
    return True

def get_top_ball(tube):
    for i in range(2, -1, -1):
        if tube[i] != 0:
            return tube[i], i
    return None, None

def remove_top_ball(tube, index):
    tube[index] = 0

def add_ball(tube, ball):
    for i in range(3):
        if tube[i] == 0:
            tube[i] = ball
            return

def solve(n, tubes):
    moves = []
    for color in range(1, n + 1):
        count = 0
        target_tube_index = None
        target_tube_ball_count = None
        for i, tube in enumerate(tubes):
            ball, index = get_top_ball(tube)
            if ball == color:
                count += 1
                if target_tube_index is None or tube.count(0) > target_tube_ball_count:
                    target_tube_index = i + 1
                    target_tube_ball_count = tube.count(0)
        for _ in range(count - 1):
            for i, tube in enumerate(tubes):
                ball, index = get_top_ball(tube)
                if ball == color:
                    remove_top_ball(tube, index)
                    add_ball(tubes[target_tube_index - 1], ball)
                    moves.append((i + 1, target_tube_index))
                    break
    return moves

def main():
    n, tubes = read_input()
    moves = solve(n, tubes)
    write_output(moves)

if __name__ == "__main__":
    main()
