import sys

def read_input():
    return sys.stdin.readline().strip()

def read_int():
    return int(read_input())

def read_ints():
    return list(map(int, read_input().split()))

def main():
    n = read_int()
    tubes = [read_ints() for _ in range(n + 1)]
    moves = []

    def find_top_non_empty_tube(tubes):
        for i, tube in enumerate(tubes):
            if tube[-1] != 0:
                return i
        return -1

    def find_tube_with_same_color(tubes, color):
        for i, tube in enumerate(tubes):
            if tube[-1] == color and len([x for x in tube if x != 0]) < 3:
                return i
        return -1

    def find_tube_with_space(tubes):
        for i, tube in enumerate(tubes):
            if len([x for x in tube if x != 0]) < 3:
                return i
        return -1

    for _ in range(20 * n):
        top_non_empty_tube_index = find_top_non_empty_tube(tubes)
        if top_non_empty_tube_index == -1:
            break
        top_ball_color = tubes[top_non_empty_tube_index][-1]
        tube_with_same_color_index = find_tube_with_same_color(tubes, top_ball_color)
        if tube_with_same_color_index == -1:
            tube_with_space_index = find_tube_with_space(tubes)
            if tube_with_space_index == -1:
                break
            moves.append((top_non_empty_tube_index + 1, tube_with_space_index + 1))
            tubes[tube_with_space_index][-len([x for x in tubes[top_non_empty_tube_index] if x == 0])] = tubes[top_non_empty_tube_index][-1]
            tubes[top_non_empty_tube_index][-1] = 0
        else:
            moves.append((top_non_empty_tube_index + 1, tube_with_same_color_index + 1))
            tubes[tube_with_same_color_index][-len([x for x in tubes[top_non_empty_tube_index] if x == 0])] = tubes[top_non_empty_tube_index][-1]
            tubes[top_non_empty_tube_index][-1] = 0

    print(len(moves))
    for move in moves:
        print(*move)

if __name__ == "__main__":
    main()
