                        new_bumps += 1
                else:
                    new_r2c -= 1
                    if (new_r2c, new_r2r) in vertical_walls or new_r2c < 0:
                        new_r2c += 1
                        new_bumps += 1

                if action == 'F':
                    new_moves = moves + 1
                else:
                    new_moves = moves

            if (new_r1c, new_r1r) == (new_r2c, new_r2r) and (new_r1c != exit_column - 1 or new_r1r != 0):
                continue

            state = (new_r1c, new_r1r, new_r1d, new_r2c, new_r2r, new_r2d)
            if state not in visited:
                visited[state] = True
                queue.append((new_r1c, new_r1r, new_r1d, new_r2c, new_r2r, new_r2d, new_moves, new_bumps))

    print(min_moves, min_bumps)

