    tubes = []
    for _ in range(n + 1):
        tube = list(map(int, input().split()))
        tubes.append(tube)
    return n, tubes

def write_output(moves):
    print(len(moves))
    for u, v in moves:
        print(u, v)

def is_solved(tubes):
    for tube in tubes:
        if len(set(tube)) > 2 or (len(set(tube)) == 2 and 0 in tube):
            return False
    return True

def get_top_ball(tube):
    for ball in reversed(tube):
        if ball != 0:
            return ball
    return 0

def solve(n, tubes):
    moves = []
    tube_balls = [set(tube) - {0} for tube in tubes]
    for color in range(1, n + 1):
        target_tube_index = None
        for i, tube in enumerate(tubes):
            if tube[0] == color and tube[1] == color and tube[2] == 0:
                target_tube_index = i + 1
                break
        if target_tube_index is None:
            for i, tube in enumerate(tubes):
                if len(tube_balls[i]) == 0:
                    target_tube_index = i + 1
                    break
        assert target_tube_index is not None
        for _ in range(3):
            source_tube_index = None
            for i, tube in enumerate(tubes):
                if color in tube_balls[i] and i + 1 != target_tube_index:
                    source_tube_index = i + 1
                    break
            if source_tube_index is None:
                break
            top_ball = get_top_ball(tubes[source_tube_index - 1])
            while top_ball != color:
                dest_tube_index = None
                for i, tube in enumerate(tubes):
                    if len(tube_balls[i]) == 0:
                        dest_tube_index = i + 1
                        break
                assert dest_tube_index is not None
                moves.append((source_tube_index, dest_tube_index))
                tubes[dest_tube_index - 1][2 - tubes[dest_tube_index - 1].count(0)] = top_ball
                tubes[source_tube_index - 1][tubes[source_tube_index - 1].index(top_ball)] = 0
                tube_balls[source_tube_index - 1].remove(top_ball)
                tube_balls[dest_tube_index - 1].add(top_ball)
                top_ball = get_top_ball(tubes[source_tube_index - 1])
            moves.append((source_tube_index, target_tube_index))
            tubes[target_tube_index - 1][2 - tubes[target_tube_index - 1].count(0)] = top_ball
            tubes[source_tube_index - 1][tubes[source_tube_index - 1].index(top_ball)] = 0
            tube_balls[source_tube_index - 1].remove(top_ball)
            tube_balls[target_tube_index - 1].add(top_ball)
    return moves

def main():
    n, tubes = read_input()
    moves = solve(n, tubes)
    write_output(moves)

if __name__ == "__main__":
    main()
