import sys

def read_input():
    return sys.stdin.readline().strip()

def read_int():
    return int(read_input())

def read_ints():
    return list(map(int, read_input().split()))

def main():
    n = read_int()
    tubes = [read_ints() for _ in range(n + 1)]
    moves = []

    for color in range(1, n + 1):
        count = sum(1 for tube in tubes if tube[0] == color or tube[1] == color or tube[2] == color)
        if count == 0:
            continue

        target_tube_index = next((i for i, tube in enumerate(tubes) if tube == [0, 0, 0]), None)
        if target_tube_index is None:
            target_tube_index = next((i for i, tube in enumerate(tubes) if tube[2] == 0 and (tube[1] == 0 or tube[1] == color) and tube[0] != 0))

        # Move balls of the current color to the target tube
        for _ in range(3):
            source_tube_index = next((i for i, tube in enumerate(tubes) if tube[-1] == color and i != target_tube_index), None)
            if source_tube_index is None:
                break
            moves.append((source_tube_index + 1, target_tube_index + 1))
            tubes[target_tube_index][tubes[target_tube_index].index(0)] = color
            tubes[source_tube_index][tubes[source_tube_index].index(color)] = 0
            tubes[target_tube_index].sort(key=lambda x: 1 if x == 0 else 0)
            tubes[source_tube_index].sort(key=lambda x: 1 if x == 0 else 0)

        # Clean up the target tube if it's not empty and not a single color
        if tubes[target_tube_index][0] != 0 and (tubes[target_tube_index][0] != tubes[target_tube_index][1] or tubes[target_tube_index][1] != tubes[target_tube_index][2]):
            for color_in_target in set(tubes[target_tube_index]):
                if color_in_target == 0:
                    continue
                for _ in range(tubes[target_tube_index].count(color_in_target)):
                    new_target_tube_index = next((i for i, tube in enumerate(tubes) if tube[-1] == 0 and i != target_tube_index), None)
                    if new_target_tube_index is None:
                        new_target_tube_index = next((i for i, tube in enumerate(tubes) if tube == [color_in_target, color_in_target, color_in_target] and i != target_tube_index), None)
                    if new_target_tube_index is not None:
                        moves.append((target_tube_index + 1, new_target_tube_index + 1))
                        tubes[new_target_tube_index][tubes[new_target_tube_index].index(0)] = color_in_target
                        tubes[target_tube_index][::-1].remove(color_in_target)
                        tubes[target_tube_index].append(0)
                        tubes[target_tube_index].sort(key=lambda x: 1 if x == 0 else 0)
                        tubes[new_target_tube_index].sort(key=lambda x: 1 if x == 0 else 0)

    print(len(moves))
    for move in moves:
        print(*move)

