import math

def calculate_min_time(s, t, blades):
    # Sort blades by maximum average piece size in descending order
    blades.sort(key=lambda x: x[0], reverse=True)

    # Initialize variables
    current_size = s
    total_time = 0.0

    # Iterate over the blades
    for m, h in blades:
        if current_size <= m:
            # Calculate the time needed to process the food to the target size
            # using the current blade
            time_needed = h * math.log2(current_size / t)
            if time_needed >= 0:
                total_time += time_needed
                current_size = t
                break
            else:
                # If the target size is already reached, stop processing
                break
        else:
            # If the current blade can't handle the current size, try to
            # process the food to the maximum size the blade can handle
            if m >= t:
                time_needed = h * math.log2(current_size / m)
                if time_needed >= 0:
                    total_time += time_needed
                    current_size = m
    if current_size > t:
        return -1
    else:
        return total_time

