import sys
from collections import deque

def hilbert(x, y, n):
    if n == 0:
        return 0
    m = 1 << (n - 1)
    h = hilbert
    if x < m and y < m:
        return h(y, x, n - 1)
    elif x < m and y >= m:
        return 2 * m * m - 1 - h(x, y - m, n - 1)
    elif x >= m and y >= m:
        return 2 * m * m + h(x - m, y - m, n - 1)
    else:
        return 4 * m * m - 1 - h(y, x - m, n - 1)

def hilbert_inv(h, n):
    if n == 0:
        return (0, 0)
    m = 1 << (n - 1)
    q = h // (m * m)
    if q == 0:
        x, y = hilbert_inv(h, n - 1)
        return (y, x)
    elif q == 1:
        x, y = hilbert_inv(2 * m * m - 1 - h, n - 1)
        return (x, y + m)
    elif q == 2:
        x, y = hilbert_inv(h - 2 * m * m, n - 1)
        return (x + m, y + m)
    else:
        x, y = hilbert_inv(4 * m * m - 1 - h, n - 1)
        return (y + m, x + m)

def is_wall(x1, y1, x2, y2, n):
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return True
    h1 = hilbert(x1, y1, n)
    h2 = hilbert(x2, y2, n)
    return (h1 // 2) != (h2 // 2)

def bfs(x, y, n):
    visited = set([(x, y)])
    queue = deque([(x, y, 0)])
    while queue:
        x, y, d = queue.popleft()
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited and not is_wall(x, y, nx, ny, n):
                if (nx, ny) in visited:
                    continue
                visited.add((nx, ny))
                queue.append((nx, ny, d + 1))
    return d

