import sys
from collections import deque

def hilbert(x, y, n):
    if n == 0:
        return 0
    n -= 1
    l = 1 << n
    if x >= 0 and x < l and y >= 0 and y < l:
        return hilbert(y, x, n)
    elif x >= 0 and x < l and y >= l and y < (l << 1):
        return l * l + hilbert(x, y - l, n)
    elif x >= l and x < (l << 1) and y >= l and y < (l << 1):
        return (l * l << 1) + hilbert(x - l, y - l, n)
    elif x >= l and x < (l << 1) and y >= 0 and y < l:
        return (l * l << 2) + hilbert(l - 1 - (y - 0), x - l, n)
    else:
        return (l * l * 3) + hilbert(l - 1 - (x - l), l - 1 - (y - l), n)

def hilbert_inv(h, n):
    if n == 0:
        return (0, 0)
    n -= 1
    l = 1 << n
    s = h >> (n << 1)
    if s == 0:
        x, y = hilbert_inv(h & ((1 << (n << 1)) - 1), n)
        return (y, x)
    elif s == 1:
        x, y = hilbert_inv(h & ((1 << (n << 1)) - 1), n)
        return (x, y + l)
    elif s == 2:
        x, y = hilbert_inv(h & ((1 << (n << 1)) - 1), n)
        return (x + l, y + l)
    elif s == 3:
        x, y = hilbert_inv(h & ((1 << (n << 1)) - 1), n)
        return (l + l - 1 - y, x + l)
    else:
        x, y = hilbert_inv(h & ((1 << (n << 1)) - 1), n)
        return (l + l - 1 - x, l + l - 1 - y)

def bfs(x1, y1, x2, y2, n):
    queue = deque([(x1, y1)])
    visited = {(x1, y1): 0}
    while queue:
        x, y = queue.popleft()
        if (x, y) == (x2, y2):
            return visited[(x, y)]
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited:
                h1 = hilbert(x, y, n)
                h2 = hilbert(nx, ny, n)
                if abs(h1 - h2) != 1:
                    visited[(nx, ny)] = visited[(x, y)] + 1
                    queue.append((nx, ny))
    return -1

def main():
    input = sys.stdin.readline
    k = int(input())
    for _ in range(k):
        n, x1, y1, x2, y2 = map(int, input().split())
        print(bfs(x1, y1, x2, y2, n))

