from collections import deque

def read_input():
    n = int(input().strip())
    tubes = []
    for _ in range(n + 1):
        b, m, t = map(int, input().strip().split())
        tubes.append([b, m, t])
    return n, tubes

def is_solved(tubes):
    for tube in tubes:
        if tube[0] != 0 and tube[0] == tube[1] == tube[2]:
            continue
        if tube[0] == tube[1] == tube[2] == 0:
            continue
        return False
    return True

def get_top_color(tube):
    for ball in reversed(tube):
        if ball != 0:
            return ball
    return 0

def get_tube_height(tube):
    count = 0
    for ball in tube:
        if ball != 0:
            count += 1
    return count

def solve(n, tubes):
    moves = []
    queue = deque([(tubes, moves)])
    visited = {tuple(tuple(tube) for tube in tubes)}
    while queue:
        current_tubes, current_moves = queue.popleft()
        if is_solved(current_tubes):
            return current_moves
        for u in range(n + 1):
            top_color = get_top_color(current_tubes[u])
            if top_color == 0:
                continue
            for v in range(n + 1):
                if u == v:
                    continue
                if get_tube_height(current_tubes[v]) == 3:
                    continue
                new_tubes = [list(tube) for tube in current_tubes]
                new_tubes[u][new_tubes[u].index(top_color)] = 0
                new_tubes[v][2 - get_tube_height(new_tubes[v])] = top_color
                new_tubes_tuple = tuple(tuple(tube) for tube in new_tubes)
                if new_tubes_tuple not in visited:
                    visited.add(new_tubes_tuple)
                    new_moves = current_moves + [(u + 1, v + 1)]
                    queue.append((new_tubes, new_moves))
    return None

def main():
    n, tubes = read_input()
    solution = solve(n, tubes)
    if solution is None:
        print("No solution found")
    else:
        print(len(solution))
        for move in solution:
            print(*move)

if __name__ == "__main__":
    main()
