    robot1_dir, robot2_dir = dir_map[robot1_dir], dir_map[robot2_dir]

    horiz_walls = set()
    n = int(input().split()[0])
    for pair in input().split():
        if n > 0:
            horiz_walls.add((int(pair), n))
            n -= 1
        else:
            n = int(pair)

    vert_walls = set()
    n = int(input().split()[0])
    for pair in input().split():
        if n > 0:
            vert_walls.add((n, int(pair)))
            n -= 1
        else:
            n = int(pair)

    queue = deque([(robot1_col, robot1_row, robot1_dir, robot2_col, robot2_row, robot2_dir, 0, 0)])
    visited = set((robot1_col, robot1_row, robot1_dir, robot2_col, robot2_row, robot2_dir))
    min_steps = float('inf')
    min_bumps = float('inf')

    while queue:
        r1c, r1r, r1d, r2c, r2r, r2d, steps, bumps = queue.popleft()

        if (r1c == exit_col and r1r == 1) or (r2c == exit_col and r2r == 1):
            if steps < min_steps or (steps == min_steps and bumps < min_bumps):
                min_steps = steps
                min_bumps = bumps
            continue

        # Turn Left
        new_r1d = (r1d - 1) % 4
        new_r2d = (r2d - 1) % 4
        new_state = (r1c, r1r, new_r1d, r2c, r2r, new_r2d)
        if new_state not in visited:
            queue.append((r1c, r1r, new_r1d, r2c, r2r, new_r2d, steps, bumps))
            visited.add(new_state)

        # Turn Right
        new_r1d = (r1d + 1) % 4
        new_r2d = (r2d + 1) % 4
        new_state = (r1c, r1r, new_r1d, r2c, r2r, new_r2d)
        if new_state not in visited:
            queue.append((r1c, r1r, new_r1d, r2c, r2r, new_r2d, steps, bumps))
            visited.add(new_state)

        # Move Forward
        new_r1c, new_r1r, new_r2c, new_r2r = r1c, r1r, r2c, r2r
        bump = 0
        if r1d == 0:  # North
            if (r1c, r1r) not in horiz_walls:
                new_r1r += 1
            else:
                bump += 1
        elif r1d == 1:  # East
            if (r1c, r1r) not in vert_walls:
                new_r1c += 1
            else:
                bump += 1
        elif r1d == 2:  # South
            if (r1c, r1r - 1) not in horiz_walls:
                new_r1r -= 1
            else:
                bump += 1
        elif r1d == 3:  # West
            if (r1c - 1, r1r) not in vert_walls:
                new_r1c -= 1
            else:
                bump += 1

        if r2d == 0:  # North
            if (r2c, r2r) not in horiz_walls:
                new_r2r += 1
            else:
                bump += 1
        elif r2d == 1:  # East
            if (r2c, r2r) not in vert_walls:
                new_r2c += 1
            else:
                bump += 1
        elif r2d == 2:  # South
            if (r2c, r2r - 1) not in horiz_walls:
                new_r2r -= 1
            else:
                bump += 1
        elif r2d == 3:  # West
            if (r2c - 1, r2r) not in vert_walls:
                new_r2c -= 1
            else:
                bump += 1

        if new_r1c == new_r2c and new_r1r == new_r2r:
            continue

        new_state = (new_r1c, new_r1r, r1d, new_r2c, new_r2r, r2d)
        if new_state not in visited:
            queue.append((new_r1c, new_r1r, r1d, new_r2c, new_r2r, r2d, steps + 1, bumps + bump))
            visited.add(new_state)

    print(min_steps, min_bumps)

